broadcast(senderId: string, room: string, message: string): void {
  for (const [id, client] of this.clients) {
    if (client.room === room && id !== senderId) {
      client.send(message);
    }
  }
}

sendPrivate(senderId: string, targetId: string, message: string): void {
  const target = this.clients.get(targetId);
  if (target) {
    target.send(message);
  }
}
